import os
import logging
from urllib.parse import unquote

import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.core.exceptions import ResourceNotFoundError

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

def get_blob_service_client():
    conn_str = os.environ["AzureWebJobsStorage"]
    return BlobServiceClient.from_connection_string(conn_str)

@app.route(route="files", methods=["GET"])
def files(req: func.HttpRequest) -> func.HttpResponse:
    logging.info("File serving request received.")

    blob_path = req.params.get("path")
    if not blob_path:
        try:
            body = req.get_json()
            blob_path = body.get("path")
        except Exception:
            blob_path = None

    if not blob_path:
        return func.HttpResponse(
            "Missing required query parameter: path",
            status_code=400
        )

    blob_path = unquote(blob_path).lstrip("/")

    container_name = os.environ.get("BLOB_CONTAINER_NAME")
    if not container_name:
        return func.HttpResponse(
            "Server configuration error: BLOB_CONTAINER_NAME is not set",
            status_code=500
        )

    try:
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        downloader = blob_client.download_blob()
        content = downloader.readall()

        props = blob_client.get_blob_properties()
        content_type = props.content_settings.content_type or "application/octet-stream"

        return func.HttpResponse(
            body=content,
            status_code=200,
            mimetype=content_type,
            headers={
                "Content-Disposition": f'inline; filename="{os.path.basename(blob_path)}"'
            }
        )
    except ResourceNotFoundError:
        return func.HttpResponse("File not found", status_code=404)
    except Exception as e:
        logging.exception("Failed to serve blob.")
        return func.HttpResponse(
            f"Internal server error: {str(e)}",
            status_code=500
        )